// ----- LAYER 2 -----
module half_adder_2(
  output S,
  output C,
  input A,
  input B
);
  assign S = A ^ B;
  assign C = A & B;
endmodule

module full_adder_2(
  output S,
  output C,
  input X,
  input Y,
  input Z
);
  wire S1, D1, D2;
  half_adder_2 HA1(.S(S1), .C(D1), .A(X), .B(Y));
  half_adder_2 HA2(.S(S), .C(D2), .A(S1), .B(Z));
  assign C = D1 | D2;
endmodule

module WddlNAND_2(
  input A,
  input B,
  input C,
  output S,
  output S1
);
  assign S = ~(A & B & C);
  assign S1 = ~S;
endmodule

module add1bit_2(
    input wire [0:0] a,
    input wire [0:0] b,
    input wire  cin,
    output wire [1:0] y,
    output wire cout,
    output wire cout_bar
);

    wire s1, s1_1, s2, s2_1, s3, s3_1, s4, s4_1;
wire c1;

full_adder_2 fa0(.S(y[0]), .C(c1), .X(a[0]), .Y(b[0]), .Z(cin));

WddlNAND_2 wn1(.A(~a[0]), .B(b[0]), .C(~c1), .S(s1), .S1(s1_1));
WddlNAND_2 wn2(.A(a[0]), .B(~b[0]), .C(~c1), .S(s2), .S1(s2_1));
WddlNAND_2 wn3(.A(a[0]), .B(b[0]), .C(c1), .S(s3), .S1(s3_1));
WddlNAND_2 wn4(.A(~a[0]), .B(~b[0]), .C(c1), .S(s4), .S1(s4_1));

assign cout = ~(s1 & s2 & s3 & s4);
assign cout_bar = ~cout;
assign y[1] = cout;

endmodule

