        if (comp2_bar)  begin stage1_2_0bar = biased_sum4_0bar; stage1_2_1bar = biased_sum4_1bar; end
        else                    begin stage1_2_0bar = biased_sum5_0bar; stage1_2_1bar = biased_sum5_1bar; end
    end

    wire [8:0] temp3_0, temp3_1, temp3_0bar, temp3_1bar;
    subtractor s3a (.A(biased_sum6_0), .B(biased_sum7_0), .Result(temp3_0));
    subtractor s3b (.A(biased_sum6_1), .B(biased_sum7_1), .Result(temp3_1));
    subtractor s3abar (.A(biased_sum6_0bar), .B(biased_sum7_0bar), .Result(temp3_0bar));
    subtractor s3bbar (.A(biased_sum6_1bar), .B(biased_sum7_1bar), .Result(temp3_1bar));
    wire comp3, comp3_bar;
    comparator_1 c3 (
        .inputs0_0(temp3_0), .inputs0_1(temp3_1),
        .r0_0(r0_3), .r1_0(r1_3), .r2_0(r2_3), .r3_0(r3_3), .r4_0(r4_3), .r5_0(r5_3), .r6_0(r6_3), .r7_0(r7_3), .r8_0(r8_3),
        .comparator(comp3)
    );
    comparator_1 c3_bar (
        .inputs0_0(temp3_0bar), .inputs0_1(temp3_1bar),
        .r0_0(r0_3bar), .r1_0(r1_3bar), .r2_0(r2_3bar), .r3_0(r3_3bar), .r4_0(r4_3bar), .r5_0(r5_3bar), .r6_0(r6_3bar), .r7_0(r7_3bar), .r8_0(r8_3bar),
        .comparator(comp3_bar)
    );
    reg [7:0] stage1_3_0, stage1_3_1, stage1_3_0bar, stage1_3_1bar;
    always @(*) begin
        if (comp3)      begin stage1_3_0 = biased_sum6_0;    stage1_3_1 = biased_sum6_1;    end
        else                    begin stage1_3_0 = biased_sum7_0;    stage1_3_1 = biased_sum7_1;    end
        if (comp3_bar)  begin stage1_3_0bar = biased_sum6_0bar; stage1_3_1bar = biased_sum6_1bar; end
        else                    begin stage1_3_0bar = biased_sum7_0bar; stage1_3_1bar = biased_sum7_1bar; end
    end

    wire [8:0] temp4_0, temp4_1, temp4_0bar, temp4_1bar;
    subtractor s4a (.A(stage1_0_0), .B(stage1_1_0), .Result(temp4_0));
