    subtractor s4abar (.A(stage1_0_0bar), .B(stage1_1_0bar), .Result(temp4_0bar));
    subtractor s4bbar (.A(stage1_0_1bar), .B(stage1_1_1bar), .Result(temp4_1bar));
    wire comp4, comp4_bar;
    comparator_1 c4 (
        .inputs0_0(temp4_0), .inputs0_1(temp4_1),
        .r0_0(r0_4), .r1_0(r1_4), .r2_0(r2_4), .r3_0(r3_4), .r4_0(r4_4), .r5_0(r5_4), .r6_0(r6_4), .r7_0(r7_4), .r8_0(r8_4),
