        else                    begin stage2_0_0bar = stage1_1_0bar; stage2_0_1bar = stage1_1_1bar; end
    end

    wire [8:0] temp5_0, temp5_1, temp5_0bar, temp5_1bar;
    subtractor s5a (.A(stage1_2_0), .B(stage1_3_0), .Result(temp5_0));
