    comparator_1 c5 (
        .inputs0_0(temp5_0), .inputs0_1(temp5_1),
        .r0_0(r0_5), .r1_0(r1_5), .r2_0(r2_5), .r3_0(r3_5), .r4_0(r4_5), .r5_0(r5_5), .r6_0(r6_5), .r7_0(r7_5), .r8_0(r8_5),
