    subtractor s6abar (.A(stage2_0_0bar), .B(stage2_1_0bar), .Result(temp6_0bar));
    subtractor s6bbar (.A(stage2_0_1bar), .B(stage2_1_1bar), .Result(temp6_1bar));
    wire comp6, comp6_bar;
    comparator_1 c6 (
        .inputs0_0(temp6_0), .inputs0_1(temp6_1),
        .r0_0(r0_6), .r1_0(r1_6), .r2_0(r2_6), .r3_0(r3_6), .r4_0(r4_6), .r5_0(r5_6), .r6_0(r6_6), .r7_0(r7_6), .r8_0(r8_6),
